/* ===== Reset & Base ===== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg-canvas:   #0d1117;
  --bg-surface:  #161b22;
  --bg-hover:    #1c2128;
  --border:      #30363d;
  --text-primary:   #e6edf3;
  --text-secondary: #8b949e;
  --text-muted:     #6e7681;
  --green:    #2ea44f;
  --green-dim: rgba(46,164,79,0.15);
  --red:      #f85149;
  --blue:     #58a6ff;
  --accent:   #388bfd;
  --radius:   6px;
}

html { scroll-behavior: smooth; }

body {
  background: var(--bg-canvas);
  color: var(--text-primary);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
  font-size: 14px;
  line-height: 1.6;
  min-height: 100vh;
}

/* ===== Layout ===== */
.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 32px 24px 64px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* ===== Header ===== */
.site-header {
  display: flex;
  align-items: center;
  gap: 16px;
  padding-bottom: 24px;
  border-bottom: 1px solid var(--border);
}

.header-icon {
  font-size: 36px;
  line-height: 1;
}

.site-header h1 {
  font-size: 24px;
  font-weight: 600;
  color: var(--text-primary);
}

.subtitle {
  color: var(--text-secondary);
  font-size: 13px;
  margin-top: 2px;
}

/* ===== Card ===== */
.card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}

.section-title {
  font-size: 16px;
  font-weight: 600;
  padding: 16px 20px;
  border-bottom: 1px solid var(--border);
  color: var(--text-primary);
}

/* ===== Table ===== */
.table-wrapper {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

thead th {
  text-align: left;
  padding: 10px 16px;
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--text-secondary);
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
}

tbody tr {
  border-bottom: 1px solid var(--border);
  cursor: pointer;
  transition: background 0.12s;
}

tbody tr:last-child { border-bottom: none; }

tbody tr:hover,
tbody tr.selected {
  background: var(--bg-hover);
}

tbody tr.selected {
  outline: 2px solid var(--accent);
  outline-offset: -2px;
}

td {
  padding: 12px 16px;
  vertical-align: middle;
}

/* Column widths */
td.rank   { width: 40px;  color: var(--text-muted); font-weight: 600; text-align: center; }
td.repo-name { white-space: nowrap; }
td.repo-name a {
  color: var(--blue);
  text-decoration: none;
  font-weight: 500;
}
td.repo-name a:hover { text-decoration: underline; }
td.repo-desc { color: var(--text-secondary); max-width: 360px; }
td.stars    { text-align: right; white-space: nowrap; font-variant-numeric: tabular-nums; }
td.delta    { text-align: right; white-space: nowrap; }

/* Delta badges */
.delta-up   { color: var(--green); font-weight: 600; }
.delta-down { color: var(--red);   font-weight: 600; }
.delta-zero { color: var(--text-muted); }
.delta-none { color: var(--text-muted); }

/* State rows */
.loading, .error {
  text-align: center;
  padding: 32px !important;
  color: var(--text-secondary);
}
.error { color: var(--red); line-height: 1.8; }

/* ===== Chart Section ===== */
.chart-section {}

.chart-hint {
  padding: 6px 20px 0;
  font-size: 12px;
  color: var(--text-muted);
}

.chart-container {
  padding: 16px 20px 20px;
  height: 280px;
  position: relative;
}

